const [nums, target] = input;
const map = {};
for (let i = 0; i < nums.length; i++) {
  const complement = target - nums[i];
  if (complement in map) return [map[complement], i];
  map[nums[i]] = i;
}
return [];

const [nums, k] = input;
let max = 0, sum = 0;
for (let i = 0; i < k; i++) sum += nums[i];
max = sum;
for (let i = k; i < nums.length; i++) {
  sum += nums[i] - nums[i - k];
  if (sum > max) max = sum;
}
return max;

const [nums, target] = input;
let left = 0, right = nums.length - 1;
while (left <= right) {
  const mid = Math.floor((left + right) / 2);
  if (nums[mid] === target) return mid;
  nums[mid] < target ? (left = mid + 1) : (right = mid - 1);
}
return -1;

const [s] = input;
let l = 0, r = s.length - 1;
while (l < r) {
  while (l < r && !/[a-zA-Z0-9]/.test(s[l])) l++;
  while (l < r && !/[a-zA-Z0-9]/.test(s[r])) r--;
  if (s[l].toLowerCase() !== s[r].toLowerCase()) return false;
  l++; r--;
}
return true;

const [s, t] = input;
if (s.length !== t.length) return false;
const count = {};
for (const c of s) count[c] = (count[c] || 0) + 1;
for (const c of t) {
  if (!count[c]) return false;
  count[c]--;
}
return true;

const [s] = input;
const set = new Set();
let max = 0, l = 0;
for (let r = 0; r < s.length; r++) {
  while (set.has(s[r])) set.delete(s[l++]);
  set.add(s[r]);
  if (r - l + 1 > max) max = r - l + 1;
}
return max;

const [arr] = input;
for (let i = 0; i < arr.length; i++) {
  let swapped = false;
  for (let j = 0; j < arr.length - i - 1; j++) {
    if (arr[j] > arr[j + 1]) {
      [arr[j], arr[j + 1]] = [arr[j + 1], arr[j]];
      swapped = true;
    }
  }
  if (!swapped) break;
}
return arr;

const [arr] = input;
function merge(a, b) {
  const r = [];
  while (a.length && b.length) r.push(a[0] < b[0] ? a.shift() : b.shift());
  return [...r, ...a, ...b];
}
function ms(a) {
  if (a.length < 2) return a;
  const m = Math.floor(a.length / 2);
  return merge(ms(a.slice(0, m)), ms(a.slice(m)));
}
return ms(arr);

const [arr] = input;
function qs(a) {
  if (a.length < 2) return a;
  const pivot = a[a.length - 1], left = [], right = [];
  for (let i = 0; i < a.length - 1; i++) a[i] < pivot ? left.push(a[i]) : right.push(a[i]);
  return [...qs(left), pivot, ...qs(right)];
}
return qs(arr);

const [nums] = input;
const seen = new Set();
for (const n of nums) {
  if (seen.has(n)) return true;
  seen.add(n);
}
return false;

const [nums] = input;
let max = nums[0], cur = nums[0];
for (let i = 1; i < nums.length; i++) {
  cur = Math.max(nums[i], cur + nums[i]);
  if (cur > max) max = cur;
}
return max;

